insert into synlte.Sameword (SAMEID, WORD, WORDNAME, ELEMNTOBJECT, MEMO, deleted) select * from (
select #{item.id, jdbcType = VARCHAR}, #{item.word, jdbcType = VARCHAR}, #{item.wordname, jdbcType = VARCHAR}, #{item.elementObject, jdbcType = VARCHAR}, #{item.memo, jdbcType = VARCHAR}, 0 from dual
)
